class Solution {
public:
    int subsequencePairCount(vector<int>& nums) {
        const int MOD=1000000007;
        const int M=200;
        vector<vector<int>>dp(M+1,vector<int>(M+1));
        dp[0][0]=1;
        for(int x:nums){
            vector<vector<int>> ndp=dp;
            for(int g1=0;g1<=M;g1++){
                for(int g2=0; g2<=M;g2++){
                    int cur=dp[g1][g2];
                    if(!cur) continue;
                    int ng1=g1 == 0 ? x:std::gcd(g1,x);
                    int &a=ndp[ng1][g2];
                    a +=cur;
                    if(a>=MOD) a-=MOD;
                    int ng2=g2==0 ? x:std::gcd(g2,x);
                    int &b=ndp[g1][ng2];
                    b+=cur;
                    if(b>=MOD) b-=MOD;
                }
            }
            dp.swap(ndp);
        }
        long long ans=0;
        for(int g=1;g<=M;g++){
            ans+=dp[g][g];
        }
        return ans%MOD;
    }
};

class Solution {
public:
    vector<int> findEvenNumbers(vector<int>& digits) {
        set<int> s;
        int n = digits.size();

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                for (int k = 0; k < n; k++) {
                    if (i != j && i != k && j != k) {
                        if (digits[i] != 0) {
                            if (digits[k] % 2 == 0) {
                                int number = digits[i] * 100 + digits[j] * 10 + digits[k];
                                s.insert(number);
                            }
                        }
                    }
                }
            }
        }
        vector<int> v = {s.begin(),s.end()};
        return v;
    }
};

class Solution {
public: 
    int totalNumbers(vector<int>& digits) {
        array<int, 10> freq={0};
        bool hasEven=0;
        for(int x: digits){
            freq[x]+=(freq[x]<3);// 3 is enough, since 3-digit number
            hasEven|=(x%2==0);
        }
    //    print(freq);
        if (!hasEven) return 0;
        int cnt=0;
        for(int i=1; i<10; i++){
            if (freq[i]==0) continue;
            freq[i]--;
            for(int j=0; j<10; j++){
                if (freq[j]==0) continue;
                freq[j]--;
                for(int k=0; k<10; k+=2){
                    if (freq[k]==0) continue;
                    cnt++;
                }
                freq[j]++;//backtrack
            }
            freq[i]++;//backtrack
        }
        return cnt;

    }
};

