class Solution {
public:
    int countCompleteComponents(int n, vector<vector<int>>& edges) {
        vector<vector<int>> adj(n);

        for (auto &e : edges) {
            adj[e[0]].push_back(e[1]);
            adj[e[1]].push_back(e[0]);
        }

        vector<bool> vis(n, false);
        int ans = 0;

        for (int i = 0; i < n; i++) {
            if (vis[i]) continue;

            queue<int> q;
            q.push(i);
            vis[i] = true;

            int nodes = 0;//number of nodes in the component
            int edgeCount = 0; //total edges in the component

            while (!q.empty()) {
                int u = q.front();
                q.pop();

                nodes++;
                edgeCount += adj[u].size();

                for (int v : adj[u]) {
                    if (!vis[v]) {
                        vis[v] = true;
                        q.push(v);
                    }
                }
            }

            edgeCount /= 2;

            if (edgeCount == nodes * (nodes - 1) / 2)
                ans++;
        }

        return ans;
    }
};

constexpr int L=18, N=1e5+1;
using int2=pair<int, int>;
int up[L][N], pos[N]; 
int2 xId[N];

class Solution {
public:
    static int cnt(int u, int v, int L) {
        if (u==v) return 0;
        if (up[0][u]>=v) return 1;
        // cannot reach v
        if (up[L-1][u]<v) return -1; 

        int step=0;
        for (int j=L-1; j>=0; j--) { 
            if (up[j][u]<v) { // Only jump when satisfied
                step+=(1<<j);
                u=up[j][u];
            }
        }
        return step+1;
    }

    vector<int> pathExistenceQueries(int n, vector<int>& nums, int maxDiff, vector<vector<int>>& queries) {
        int maxL=bit_width((unsigned)n)+1;
        for(int i=0; i<n; i++) 
            xId[i]={nums[i], i};

        sort(xId, xId+n);
        for (int i=0; i<n; i++)// pos of index in sorted xId
            pos[xId[i].second]=i;

        //sliding window 
        for (int l=0, r=0; l<n; l++) {
            while (r+1<n && xId[r+1].first-xId[l].first<=maxDiff) 
                r++;
            up[0][l]=r;
        }

        // Compute binary lifting tables
        for (int j=1; j<maxL; j++) {
            for (int i=0; i<n; i++) {
                up[j][i]=up[j-1][up[j-1][i]];
            }
        }

        const int qz=queries.size();
        vector<int> ans(qz);
        int i=0;
        for (auto& q : queries) {
            auto [u, v]=minmax(pos[q[0]], pos[q[1]]);
            ans[i++]=cnt(u, v, maxL);
        }
        return ans;
    }
};

