class Solution
{
public:
    using u32 = uint32_t;
    inline static constexpr u32 kMOD = 1'000'000'007;

    [[nodiscard, gnu::target("bmi2,avx2")]] constexpr std::vector<int>
    pathsWithMaxScore(std::vector<std::string>& board) noexcept
    {
        const u32 h = static_cast<u32>(board.size()), h1 = h - 1;
        const u32 w = static_cast<u32>(board[0].size()), w1 = w - 1;
        u32 dp[100][2];

        auto f = [&] [[gnu::always_inline]] (u32 & s, u32 & p, u32 x, u32 y)
        {
            char c = board[y][x];
            bool is_obstacle = c == 'X';
            bool is_number = c >= '0' && c <= '9';
            s += ((c - '0') & -is_number) & 0xF;
            s &= -u32{!is_obstacle && !!p};
            p &= -u32{!is_obstacle};
        };

        // There is no number at the bottom right corner
        // and only one way to get there
        dp[w1][0] = 0, dp[w1][1] = 1;

        // handle the last row except bottom right cell
        for (u32 x = w1, sr = dp[x][0], pr = dp[x][1]; x--;)
        {
            auto& [s, p] = dp[x];
            f(s = sr, p = pr, x, h1);
            sr = s, pr = p;
        }

        // handle rows [0; h-1]
        for (u32 y = h1; y--;)
        {
            auto [s3, p3] = dp[w1];

            // handle last element
            f(dp[w1][0] = s3, dp[w1][1] = p3, w1, y);

            // base case y ∈ [0; h-1], x ∈ [0; w-1]
            for (u32 x = w1; x--;)
            {
                auto [s, p] = dp[x];
                auto [s1, p1] = dp[x + 1];
                auto [s2, p2] = dp[x];
                s = std::max(s1, std::max(s2, s3));
                p = (p1 & -u32{s == s1})
                  + (p2 & -u32{s == s2})
                  + (p3 & -u32{s == s3});
                p -= kMOD & -u32{p >= kMOD};
                p -= kMOD & -u32{p >= kMOD};
                f(s, p, x, y);
                s3 = dp[x][0], p3 = dp[x][1];
                dp[x][0] = s, dp[x][1] = p;
            }
        }

        return {static_cast<int>(dp[0][0]), static_cast<int>(dp[0][1])};
    }
};

class Solution {
public:
    int minScore(int n, vector<vector<int>>& roads) {
        vector<vector<pair<int,int>>> adj(n + 1);

        for(auto &road : roads){
            int u = road[0];
            int v = road[1];
            int w = road[2];

            adj[u].push_back({v, w});
            adj[v].push_back({u, w});
        }

        vector<bool> vis(n + 1, false);
        queue<int> q;

        q.push(1);
        vis[1] = true;

        int ans = INT_MAX;

        while(!q.empty()){

            int node = q.front();
            q.pop();

            for(auto &[nei, wt] : adj[node]){

                ans = min(ans, wt);

                if(!vis[nei]){
                    vis[nei] = true;
                    q.push(nei);
                }
            }
        }

        return ans;
    }
};

class Solution {
public:
    int n;

    bool find(int limit, unordered_map<int, vector<pair<int,int>>>& adj,
              vector<bool>& online, vector<int>& topoSort, long long k){

        vector<long long> dist(n, LLONG_MAX);
        dist[0] = 0;

        for(int node : topoSort){
            if(dist[node] == LLONG_MAX) continue;

            for(auto &nxt : adj[node]){
                int nxtNode = nxt.first;
                int cst = nxt.second;

                if(cst < limit) continue;

                if(nxtNode != n-1 && !online[nxtNode]) continue;

                dist[nxtNode] = min(dist[nxtNode], dist[node] + cst);
            }
        }

        return dist[n-1] <= k;
    }

    int findMaxPathScore(vector<vector<int>>& edges, vector<bool>& online, long long k) {
        n = online.size();
        unordered_map<int, vector<pair<int,int>>> adj;

        vector<int> indegree(n, 0);

        int low = INT_MAX;
        int high = 0;

        for(auto &e : edges){
            int u = e[0];
            int v = e[1];
            int cst = e[2];

            adj[u].push_back({v, cst});
            indegree[v]++;

            low = min(low, cst);
            high = max(high, cst);
        }

        queue<int> q;
        vector<int> topoSort;

        for(int i=0;i<n;i++){
            if(indegree[i] == 0){
                q.push(i);
            }
        }

        while(!q.empty()){
            int node = q.front();
            q.pop();

            topoSort.push_back(node);

            for(auto &ngbr : adj[node]){
                int nxtNode = ngbr.first;

                indegree[nxtNode]--;

                if(indegree[nxtNode] == 0){
                    q.push(nxtNode);
                }
            }
        }

        int res = -1;

        while(low <= high){
            int mid = low + (high - low)/2;

            if(find(mid, adj, online, topoSort, k)){
                res = mid;
                low = mid + 1;
            }
            else{
                high = mid - 1;
            }
        }

        return res;
    }
};

typedef tuple<int, int, int> iii;

class Solution {
public:
    bool findSafeWalk(vector<vector<int>>& g, int health) {
        int m = g.size(), n = g[0].size();
        priority_queue<iii, vector<iii>, greater<iii>> pq;
        pq.push({g[0][0], 0, 0});

        vector<vector<int>> d(m, vector<int> (n, INT_MAX));
        int dx[] = {-1, 1, 0, 0}, dy[] = {0, 0, -1, 1};
        d[0][0] = g[0][0];

        while(!pq.empty()){
            auto [curr, x, y] = pq.top();
            pq.pop();

            if(curr > d[x][y]) continue;
            for(int k=0; k<4; k++){
                int nx = x+dx[k], ny = y+dy[k];
                if(nx<0 || ny<0 || nx>m-1 || ny>n-1) continue;
                if(curr + g[nx][ny] < d[nx][ny]){
                    d[nx][ny] = curr + g[nx][ny];
                    pq.push({d[nx][ny], nx, ny});
                }
            }
        }

        return health > d[m-1][n-1];
    }
};

// union find class with rank
const int N=160000;
int Root[N], Rank[N];
static int d[5] = {0, 1, 0, -1, 0};
class UnionFind {
public:
    UnionFind(int n){
        iota(Root, Root+n, 0);
        memset(Rank, 0, n*sizeof(int));
    }

    int Find(int x) {
        return (x == Root[x])? x :Root[x]=Find(Root[x]);
    }

    bool Union(int x, int y) {
        x=Find(x), y=Find(y);
        if (x==y) return 0;
        if (Rank[x] > Rank[y]) swap(x, y);
        Root[x] = y;
        if (Rank[x] == Rank[y])
            Rank[y]++;
        return 1;
    }
    bool connected(int x, int y) { return Find(x) == Find(y); }
};

