            }
        }
        memset(L1, -1, 2*n*sizeof(int));
        memset(nxt, -1, n*n*sizeof(int));

        int dist = 0;
        while (front<back) {
            int qz = back-front;
            for (int a = 0; a < qz; a++) {
                auto [i, j] = q[front++];
                for (int b = 0; b < 4; b++) {
                    int r = i + d[b], c = j + d[b + 1];
                    if (r < 0 || r >= n || c < 0 || c >= n || grid[r][c] != -1)
                        continue;
                    grid[r][c] = dist + 1;
                    q[back++]={r, c};
                    insert(dist + 1, to1d(r, c, n));
                }
            }
            dist++;
        }

        UnionFind G(n * n);
        for (int dd = dist - 1; dd >= 0; dd--) {
            if (L1[dd]==-1)
                continue;
            for (int idx=L1[dd]; idx!=-1; idx=nxt[idx]) {
                auto [i, j]=div(idx, n);
                for (int b = 0; b < 4; b++) {
                    int r = i + d[b], c = j + d[b + 1];
                    if (r < 0 || r >= n || c < 0 || c >= n)
                        continue;
                    if (grid[r][c] >= dd)
                        G.Union(to1d(i, j, n), to1d(r, c, n));
                }
            }
            if (G.connected(0, n * n - 1))
                return dd;
        }
        return 0;
    }
};

