class Solution {
public:
    static constexpr int MOD = 1000000007;

    vector<vector<long long>> multiply(
        const vector<vector<long long>>& A,
        const vector<vector<long long>>& B) {

        int n = A.size();

        vector<vector<long long>> C(
            n, vector<long long>(n, 0));

        for (int i = 0; i < n; i++) {
            for (int k = 0; k < n; k++) {

                if (A[i][k] == 0) continue;

                for (int j = 0; j < n; j++) {

                    if (B[k][j] == 0) continue;

                    C[i][j] =
                        (C[i][j] +
                         A[i][k] * B[k][j]) % MOD;
                }
            }
        }

        return C;
    }

    vector<vector<long long>> power(
        vector<vector<long long>> base,
        long long exp) {

        int n = base.size();

        vector<vector<long long>> res(
            n, vector<long long>(n, 0));

        for (int i = 0; i < n; i++) {
            res[i][i] = 1;
        }

        while (exp) {

            if (exp & 1)
                res = multiply(res, base);

            base = multiply(base, base);
            exp >>= 1;
        }

        return res;
    }

    int zigZagArrays(int n, int l, int r) {

        int m = r - l + 1;

        if (n == 1)
            return m;

        int states = 2 * m;

        vector<vector<long long>> T(
            states,
            vector<long long>(states, 0));

        for (int a = 0; a < m; a++) {
            for (int b = 0; b < m; b++) {

                if (a == b) continue;

                if (a < b) {
                    T[a][m + b] = 1;
                } else {
                    T[m + a][b] = 1;
                }
            }
        }

        auto P = power(T, n - 1);

        vector<long long> start(states, 1);

        long long ans = 0;

        for (int i = 0; i < states; i++) {
            for (int j = 0; j < states; j++) {

                ans =
                    (ans +
                     start[i] * P[i][j]) % MOD;
            }
        }

        return (int)ans;
    }
};

class Solution {
public:
    int zigZagArrays(int n, int l, int r) {
        int mod = 1'000'000'007;
        int m = r-l+1;
        vector<int> dp(m, 1);
        while (--n) {
            long long sum = 0;
            for (auto& x : dp) {
                int cur = x;
                x = sum % mod, sum += cur;
            }
            reverse(begin(dp), end(dp));
        }
        return 2*reduce(begin(dp), end(dp), 0LL) % mod;
    }
};

class Solution {
public:
    double largestTriangleArea(vector<vector<int>>& points) {

        double maxArea = 0;

        int n = points.size();

        for (int i = 0; i < n; i++) {

            for (int j = i + 1; j < n; j++) {

                for (int k = j + 1; k < n; k++) {

                    int x1 = points[i][0];
                    int y1 = points[i][1];

                    int x2 = points[j][0];
                    int y2 = points[j][1];

                    int x3 = points[k][0];
                    int y3 = points[k][1];

                    double area =
                    abs(
                        x1 * (y2 - y3)
                      + x2 * (y3 - y1)
                      + x3 * (y1 - y2)
                    ) / 2.0;

                    maxArea = max(maxArea, area);
                }
            }
        }

        return maxArea;
    }
};

class Solution {
public:
    int maxPoints(vector<vector<int>>& points) {
        int best = 1;

        for (auto& p1 : points) {
            int seen_slopes[5903] = {};

            for (auto& p2 : points) {
                if (&p1 == &p2) continue;

                int dx = p2[0] - p1[0];
                int dy = p2[1] - p1[1];
                if (dx < 0) {
                    dx = -dx;
                    dy = -dy;
                }
                int div = dx > dy ? gcd(dx, dy) : gcd(dy, dx);
                dx /= div;
                dy /= div;

                unsigned long long dx_bits = *((unsigned int*) &dx);
                unsigned long long dy_bits = *((unsigned int*) &dy);
                unsigned long long key = ((dx_bits << 32) | dy_bits) % 5903;
                seen_slopes[key]++;

                best = max(best, seen_slopes[key] + 1);
            }
        }

        return best;
    }

    int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b); 
    }
};

