class Solution {
public:
    char processStr(string s, long long k) {
        long long len = 0;

        // Step 1: compute final length
        for (char c : s) {
            if (c == '*') {
                len = max(0LL, len - 1);
            }
            else if (c == '#') {
                len *= 2;
            }
            else if (c != '%') {
                len++;
            }
        }

        // boundary check
        if (k >= len) return '.';

        // Step 2: backward simulation
        for (int i = (int)s.size() - 1; i >= 0; i--) {
            char c = s[i];

            if (c == '*') {
                len++;
            }

            else if (c == '#') {
                long long half = len / 2;

                if (k >= half) {
                    k -= half;
                }

                len = half;
            }

            else if (c == '%') {
                k = len - 1 - k;
            }

            else {
                if (k == len - 1) {
                    return c;
                }
                len--;
            }
        }

        return '.';
    }
};

class Solution {
public:
    string processStr(string s) {
        deque<char> dq;
        bool rev = false;

        for (char ch : s) {

            if (ch >= 'a' && ch <= 'z') {
                if (!rev) dq.push_back(ch);
                else dq.push_front(ch);
            }

            else if (ch == '*') {
                if (!dq.empty()) {
                    if (!rev) dq.pop_back();
                    else dq.pop_front();
                }
            }

            else if (ch == '%') {
                rev = !rev;
            }

            else if (ch == '#') {
                if (dq.empty()) continue;

                deque<char> copy = dq;

                if (!rev) {
                    for (char c : copy)
                        dq.push_back(c);
                } else {
                    for (auto it = copy.rbegin(); it != copy.rend(); it++)
                        dq.push_front(*it);
                }
            }
        }

        string ans;

        if (!rev) {
            for (char c : dq) ans += c;
        } else {
            for (auto it = dq.rbegin(); it != dq.rend(); it++)
                ans += *it;
        }

        return ans;
    }
};

class Solution {
public:
    ListNode* deleteMiddle(ListNode* head) {

        if(head == nullptr || head->next == nullptr)
            return nullptr;

        ListNode* slow = head;
        ListNode* fast = head;
        ListNode* prev = nullptr;

        while(fast && fast->next){
            prev = slow;
            slow = slow->next;
            fast = fast->next->next;
        }

        prev->next = slow->next;

        delete slow;

        return head;
    }
};

class Solution {
public:
    int pairSum(ListNode* head) {

        ListNode* slow = head;
        ListNode* fast = head;

        while (fast && fast->next) {
            slow = slow->next;
            fast = fast->next->next;
        }

        ListNode* prev = nullptr;

        while (slow) {
            ListNode* nxt = slow->next;
            slow->next = prev;
            prev = slow;
            slow = nxt;
        }

        int ans = 0;

        ListNode* first = head;
        ListNode* second = prev;

        while (second) {
            ans = max(ans, first->val + second->val);
            first = first->next;
            second = second->next;
        }

        return ans;
    }
};

