class Solution {
public:
    static constexpr int MOD = 1e9 + 7;
    static constexpr int LOG = 17;

    vector<int> assignEdgeWeights(vector<vector<int>>& edges,
                                  vector<vector<int>>& queries) {

        int n = edges.size() + 1;

        vector<vector<int>> adj(n + 1);

        for (auto& e : edges) {
            int u = e[0];
            int v = e[1];

            adj[u].push_back(v);
            adj[v].push_back(u);
        }

        vector<int> depth(n + 1, 0);
        vector<vector<int>> up(LOG + 1,
                               vector<int>(n + 1, -1));

        function<void(int,int)> dfs = [&](int u, int p) {

            up[0][u] = p;

            for (int v : adj[u]) {
                if (v == p) continue;

                depth[v] = depth[u] + 1;
                dfs(v, u);
            }
        };

        dfs(1, -1);

        for (int k = 1; k <= LOG; k++) {
            for (int v = 1; v <= n; v++) {

                if (up[k - 1][v] != -1) {
                    up[k][v] =
                        up[k - 1][up[k - 1][v]];
                }
            }
        }

        auto lca = [&](int a, int b) {

            if (depth[a] < depth[b])
                swap(a, b);

            int diff = depth[a] - depth[b];

            for (int k = LOG; k >= 0; k--) {
                if ((diff >> k) & 1)
                    a = up[k][a];
            }

            if (a == b)
                return a;

            for (int k = LOG; k >= 0; k--) {

                if (up[k][a] != up[k][b]) {
                    a = up[k][a];
                    b = up[k][b];
                }
            }

            return up[0][a];
        };

        vector<long long> pow2(n + 1, 1);

        for (int i = 1; i <= n; i++) {
            pow2[i] = (pow2[i - 1] * 2) % MOD;
        }

        vector<int> ans;

        for (auto& q : queries) {

            int u = q[0];
            int v = q[1];

            int p = lca(u, v);

            int len =
                depth[u] + depth[v] - 2 * depth[p];

            if (len == 0)
                ans.push_back(0);
            else
                ans.push_back(pow2[len - 1]);
        }

        return ans;
    }
};

class Solution {
public:
    static const int MOD = 1e9 + 7;

    int dfs(vector<vector<int>>& adj, int node, int par) {
        int depth = 0;

        for (auto &child : adj[node]) {
            if (child == par) continue;
            depth = max(depth, 1 + dfs(adj, child, node));
        }

        return depth;
    }

    int assignEdgeWeights(vector<vector<int>>& edges) {
