        int l=0,r=1,n=numbers.size(),s1=numbers[l];
        while(r<n-1 && numbers[r]+s1<target) ++r;
        if(numbers[r]+s1==target) return {++l, ++r};
        int s2=numbers[r];
        while(l<r){
            if(s2+s1>target) { s2=numbers[--r];} 
            else if(s2+s1<target) {s1=numbers[++l];}
            else return {++l,++r};
        }
        return {++l,++r};
    }
};

