class Solution {
public: 
    void rotate(vector<int>& nums, int k) {
        int size = nums.size();
        k %= size;
        int i,j,mod;
        while(k!=0){
            i=k;
            j=0;
            mod=size%k;
            while(i<size){
                swap(nums[i++],nums[j++]);
                j%=k;
            }
            if(!mod) break;
            size=k;
            k=k-mod;
        }
    }
};

