        std::size_t left = 0, right = height.size() - 1;
        int left_max = 0, right_max = 0;
        long long water = 0LL;

        while (left < right) {
            if (height[left] < height[right]) {
                if (height[left] >= left_max) {
                    left_max = height[left];
                } else {
                    water += left_max - height[left];
                }
                ++left;

