class Solution {
public:
    int strStr(string haystack, string needle) {
        // if (haystack == needle)
        //     return 0;
        int l = haystack.size() - needle.size() + 1;
        for (int i = 0; i < l; i++) {
            if (haystack[i] == needle[0]) {
                int j = i + 1;
                for (int k = 1; k < needle.size(); k++) {
                    if (haystack[j] != needle[k])
                        continue;
                    j++;
                }
                if((j-i)==needle.size()){
                    return i;
                }
            }
        }
        return -1;
    }
};

class Solution {
public:
    int climbStairs(int n) {
        int dp[n+1];
        if(n==1){return 1;}
        if(n==2){return 2;}
        dp[1]=1;
        dp[2]=2;
        for(int i=3;i<=n;i++){
            dp[i]=dp[i-1]+dp[i-2];
        }
        return dp[n];
    }
};

