class Solution {
public:
    bool canReach(string s, int minJump, int maxJump) {

        int n = s.size();

        queue<int> q;

        q.push(0);

        int farthest = 0;

        while (!q.empty()) {

            int i = q.front();
            q.pop();

            int start = max(i + minJump, farthest + 1);
            int end = min(i + maxJump, n - 1);

            for (int j = start; j <= end; j++) {

                if (s[j] == '0') {

                    if (j == n - 1)
                        return true;

                    q.push(j);
                }
            }

            farthest = i + maxJump;
        }

        return n == 1;
    }
};

/**
 * Forward declaration of guess API.
 * @param  num   your guess
 * @return 	     -1 if num is higher than the picked number
 *			      1 if num is lower than the picked number
 *               otherwise return 0
 * int guess(int num);
 */

class Solution {
public:
    int guessNumber(int n) {
        int l = 1, r = n;
        while (l <= r) {
            int m = ((l - r) / 2) + r;
            if (guess(m) == -1)
                r = m - 1;
            else if (guess(m) == 1)
                l = m + 1;
            else
                return m;
        }
        return -1;
    }
};

