class Solution {
public:
    int firstBadVersion(int n) {
        long long  low = 1 ;
        long long  high = n ;
        long long  ans ;
        while(low<=high){
            long long  mid = (low +high)/2;
            if(isBadVersion((int)mid)) {ans = mid ; high = mid - 1;}
            else low = mid + 1;
        }
        return (int)ans ;
    }
