class Solution {
public:
    int search(vector<int>& nums, int target) {
        int r = nums.size()-1;
        int l = 0;
        while (l<=r){
            int mid = l+ (r-l)/2;
            if (nums[mid] == target){
                return mid;
            }
            if (nums[l] <= nums[mid] ){
                if(target >= nums[l] && target < nums[mid]){

            r = mid - 1;
                }
                else{

            l = mid + 1;
                     }
            }
            else    {
                if(target> nums[mid]&&target <=nums[r]){
                    l = mid+1;
                }
                else {
                    r = mid-1;
                }
            }

        }
        return -1;
    }
};

class Solution {
