        int t=0;
        while(t<36){
            long long val=(long long)num1-(long long)t*num2;
            if(val<0) return -1;

            if(__builtin_popcountll(val)<=t&&t<=val){
                return t;
            }
            t++;
        }
        return -1;
    }
